using System;
using System.Drawing;
using System.IO;

namespace Kiosk
{
    public static class PayImages
    {
        private static Image FromBase64(string b64)
        {
            byte[] bytes = Convert.FromBase64String(b64);
            var ms = new MemoryStream(bytes);
            return Image.FromStream(ms);
        }

        public static Image GetImage(string method)
        {
            switch (method)
            {
                case "카카오페이": return FromBase64(KAKAO_B64);
                case "네이버페이": return FromBase64(NAVER_B64);
                case "신용카드": return FromBase64(CARD_B64);
                default: return null;
            }
        }

        private const string KAKAO_B64 = "";

        private const string NAVER_B64 = "";

        private const string CARD_B64 = "";
    }
}
